  // Members Directory - Trust Circle
  app.get("/api/members/directory", async (req, res) => {
    try {
      const { q, location } = req.query;
      const searchQuery = typeof q === 'string' ? q.toLowerCase().trim() : '';
      const locationQuery = typeof location === 'string' ? location.toLowerCase().trim() : '';

      // Get all verified members with basic public profile info
      const allMembers = await db.select({
        id: users.id,
        displayName: users.username,
        createdAt: users.createdAt,
      }).from(users)
        .orderBy(users.id)
        .limit(200);

      // Map with real member numbers and filter by search query
      let formattedMembers = allMembers.map((m, idx) => ({
        id: m.id,
        displayName: m.displayName || `Member #${idx + 1}`,
        memberNumber: idx + 1,
        location: null as string | null, // Will be populated when profile system is complete
        businessType: null as string | null,
        isVerified: true,
        isEarlyAdopter: idx < 500,
        joinedAt: m.createdAt?.toISOString() || new Date().toISOString(),
      }));

      // Apply search filter
      if (searchQuery) {
        formattedMembers = formattedMembers.filter(m =>
          m.displayName.toLowerCase().includes(searchQuery) ||
          `member #${m.memberNumber}`.includes(searchQuery)
        );
      }

      // Apply location filter (for future when profiles have location data)
      if (locationQuery) {
        formattedMembers = formattedMembers.filter(m =>
          m.location && m.location.toLowerCase().includes(locationQuery)
        );
      }

      res.json({
        members: formattedMembers.slice(0, 100),
        total: formattedMembers.length
      });
    } catch (error) {
      console.error("Members directory error:", error);
      res.json({ members: [], total: 0 });
    }
  });

  // Business Membership Application
  app.post("/api/business/apply", verifyFirebaseToken, async (req: AuthenticatedRequest, res) => {
    try {
      const userId = req.user?.id || req.firebaseUser?.uid;
      if (!userId) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const {
        businessName,
        einNumber,
        website,
        contactName,
        contactEmail,
        contactPhone,
        businessDescription,
        intendedUse,
        employeeCount,
        country
      } = req.body;

      if (!businessName || !einNumber || !contactEmail || !businessDescription) {
        return res.status(400).json({ error: "Missing required fields" });
      }

      // Check if user already has a pending or approved application
      const existingApp = await db.select().from(businessApplications)
        .where(eq(businessApplications.userId, userId))
        .limit(1);

      if (existingApp.length > 0) {
        const app = existingApp[0];
        if (app.status === "approved") {
          return res.status(400).json({ error: "You already have an approved business account" });
        }
        if (app.status === "pending") {
          return res.status(400).json({ error: "You already have a pending application" });
        }
      }

      // Create the application
      const [application] = await db.insert(businessApplications).values({
        userId,
        businessName,
        einNumber,
        website: website || null,
        contactName,
        contactEmail,
        contactPhone: contactPhone || null,
        businessDescription,
        intendedUse: intendedUse || null,
        employeeCount: employeeCount || null,
        country: country || "United States",
      }).returning();

      console.log(`[Business] New application submitted: ${businessName} by ${userId}`);

      res.json({
        success: true,
        applicationId: application.id,
        status: "pending",
        message: "Application submitted successfully. We will review within 2-3 business days."
      });
    } catch (error: any) {
      console.error("Business application error:", error);
      res.status(500).json({ error: "Failed to submit application" });
    }
  });

