  // Text-to-Speech for book reader (public - no auth required)
  // Priority: ElevenLabs (Rachel) → OpenAI (Nova) → client browser fallback
  app.post("/api/voice/tts", async (req: any, res) => {
    try {
      const { text, voice } = req.body;

      if (!text || text.length === 0) {
        return res.status(400).json({ error: "Text is required" });
      }

      if (text.length > 5000) {
        return res.status(400).json({ error: "Text too long. Maximum 5000 characters per request." });
      }

      const elevenLabsKey = process.env.ELEVEN_LABS_API_KEY;
      const elevenLabsVoiceId = voice || "pFZP5JQG7iQjIQuC4Bku";
      if (elevenLabsKey) {
        try {
          const elAbort = new AbortController();
          const elTimeout = setTimeout(() => elAbort.abort(), 20000);
          const elResponse = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${elevenLabsVoiceId}`, {
            method: "POST",
            headers: {
              "xi-api-key": elevenLabsKey,
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text,
              model_id: "eleven_multilingual_v2",
              voice_settings: {
                stability: 0.5,
                similarity_boost: 0.75,
                style: 0.4,
                use_speaker_boost: true,
              },
            }),
            signal: elAbort.signal,
          });
          clearTimeout(elTimeout);

          if (elResponse.ok) {
            console.log("[TTS] ElevenLabs served successfully");
            const arrayBuffer = await elResponse.arrayBuffer();
            res.set({
              "Content-Type": "audio/mpeg",
              "Cache-Control": "public, max-age=86400",
              "X-Voice-Provider": "elevenlabs",
              "X-Voice-Name": "Lily",
            });
            return res.send(Buffer.from(arrayBuffer));
          }

          const elError = await elResponse.text().catch(() => "");
          console.error("[TTS] ElevenLabs failed, falling back to OpenAI:", elResponse.status, elError);
        } catch (elErr: any) {
          console.error("[TTS] ElevenLabs error, falling back to OpenAI:", elErr.message);
        }
      }

      const openaiKey = process.env.OPENAI_API_KEY;
      if (!openaiKey) {
        return res.status(503).json({ error: "Voice service not configured", fallback: true });
      }

      const oaiAbort = new AbortController();
      const oaiTimeout = setTimeout(() => oaiAbort.abort(), 30000);
      const response = await fetch("https://api.openai.com/v1/audio/speech", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${openaiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: "tts-1",
          input: text,
          voice: "nova",
          response_format: "mp3",
        }),
        signal: oaiAbort.signal,
      });
      clearTimeout(oaiTimeout);

      if (!response.ok) {
        const errorText = await response.text();
        console.error("[TTS] OpenAI Nova failed:", response.status, errorText);
        return res.status(response.status).json({
          error: "Voice generation failed",
          fallback: true,
          details: errorText
        });
      }

      console.log("[TTS] OpenAI Nova served as fallback");
      res.set({
        "Content-Type": "audio/mpeg",
        "Cache-Control": "public, max-age=86400",
        "X-Voice-Provider": "openai",
        "X-Voice-Name": "Nova",
      });

      const arrayBuffer = await response.arrayBuffer();
      res.send(Buffer.from(arrayBuffer));

    } catch (error: any) {
      console.error("[TTS] Error:", error);
      res.status(500).json({ error: error.message || "Voice generation failed", fallback: true });
    }
  });

