  // ML Stats - Overall prediction system statistics
  app.get("/api/ml/stats", pulseDataRateLimit, async (req: any, res) => {
    try {
      // Get total predictions count
      const totalPredictions = await db.select({ count: sql`count(*)` })
        .from(predictionEvents);

      // Get outcomes count
      const totalOutcomes = await db.select({ count: sql`count(*)` })
        .from(predictionOutcomes);

      // Get overall accuracy
      const accuracyStats = await db.select({
        total: sql`count(*)`,
        wins: sql`count(*) filter (where is_correct = true)`,
        avgReturn: sql`avg(cast(price_change_percent as decimal))`
      }).from(predictionOutcomes);

      // Get accuracy by horizon
      const horizonStats = await db.select({
        horizon: predictionOutcomes.horizon,
        count: sql`count(*)`,
        wins: sql`count(*) filter (where is_correct = true)`,
        avgReturn: sql`avg(cast(price_change_percent as decimal))`
      })
        .from(predictionOutcomes)
        .groupBy(predictionOutcomes.horizon);

      // Get recent performance (last 24h, 7d, 30d)
      const now = new Date();
      const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
      const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

      const last24h = await db.select({
        total: sql`count(*)`,
        wins: sql`count(*) filter (where is_correct = true)`
      })
        .from(predictionOutcomes)
        .where(gte(predictionOutcomes.evaluatedAt, oneDayAgo));

      const last7d = await db.select({
        total: sql`count(*)`,
        wins: sql`count(*) filter (where is_correct = true)`
      })
        .from(predictionOutcomes)
        .where(gte(predictionOutcomes.evaluatedAt, sevenDaysAgo));

      const last30d = await db.select({
        total: sql`count(*)`,
        wins: sql`count(*) filter (where is_correct = true)`
      })
        .from(predictionOutcomes)
        .where(gte(predictionOutcomes.evaluatedAt, thirtyDaysAgo));

      // Get top performing tokens by joining with predictionEvents for ticker
      const topTokens = await db.select({
        ticker: predictionEvents.ticker,
        count: sql`count(*)`,
        wins: sql`count(*) filter (where ${predictionOutcomes.isCorrect} = true)`,
        avgReturn: sql`avg(cast(${predictionOutcomes.priceChangePercent} as decimal))`
      })
        .from(predictionOutcomes)
        .innerJoin(predictionEvents, eq(predictionOutcomes.predictionId, predictionEvents.id))
        .groupBy(predictionEvents.ticker)
        .having(sql`count(*) >= 3`)
        .orderBy(sql`count(*) filter (where ${predictionOutcomes.isCorrect} = true)::float / nullif(count(*), 0) desc`)
        .limit(10);

      // Helper to safely compute accuracy percentage
      const computeAccuracy = (wins: any, total: any): string => {
        const numTotal = Number(total || 0);
        const numWins = Number(wins || 0);
        return numTotal > 0 ? ((numWins / numTotal) * 100).toFixed(1) : '0.0';
      };

      const stats = {
        overview: {
          totalPredictions: Number(totalPredictions[0]?.count || 0),
          totalResolved: Number(totalOutcomes[0]?.count || 0),
          pendingResolution: Number(totalPredictions[0]?.count || 0) - Number(totalOutcomes[0]?.count || 0),
          overallAccuracy: computeAccuracy(accuracyStats[0]?.wins, accuracyStats[0]?.total),
          avgReturn: Number(accuracyStats[0]?.avgReturn || 0).toFixed(2)
        },
        byHorizon: horizonStats.map(h => ({
          horizon: h.horizon,
          predictions: Number(h.count || 0),
          wins: Number(h.wins || 0),
          accuracy: computeAccuracy(h.wins, h.count),
          avgReturn: Number(h.avgReturn || 0).toFixed(2)
        })),
        recentPerformance: {
          last24h: {
            predictions: Number(last24h[0]?.total || 0),
            accuracy: computeAccuracy(last24h[0]?.wins, last24h[0]?.total)
          },
          last7d: {
            predictions: Number(last7d[0]?.total || 0),
            accuracy: computeAccuracy(last7d[0]?.wins, last7d[0]?.total)
          },
          last30d: {
            predictions: Number(last30d[0]?.total || 0),
            accuracy: computeAccuracy(last30d[0]?.wins, last30d[0]?.total)
          }
        },
        topTokens: topTokens.map(t => ({
          symbol: t.ticker,
          predictions: Number(t.count || 0),
          wins: Number(t.wins || 0),
          accuracy: computeAccuracy(t.wins, t.count),
          avgReturn: Number(t.avgReturn || 0).toFixed(2)
        })),
        generatedAt: new Date().toISOString()
      };

      res.json(stats);
    } catch (error) {
      console.error("ML stats error:", error);
      res.status(500).json({ error: "Failed to fetch ML statistics" });
    }
  });

  // ML User History - Prediction history for a specific user
  app.get("/api/ml/user-history", pulseDataRateLimit, isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const limit = Math.min(parseInt(req.query.limit) || 50, 100);
      const offset = parseInt(req.query.offset) || 0;

      // Get user's predictions with outcomes
      const predictions = await db.select({
        id: predictionEvents.id,
        ticker: predictionEvents.ticker,
        signal: predictionEvents.signal,
        confidence: predictionEvents.confidence,
        priceAtPrediction: predictionEvents.priceAtPrediction,
        createdAt: predictionEvents.createdAt,
        horizon: predictionOutcomes.horizon,
        isCorrect: predictionOutcomes.isCorrect,
        priceChangePercent: predictionOutcomes.priceChangePercent,
        evaluatedAt: predictionOutcomes.evaluatedAt,
      })
        .from(predictionEvents)
        .leftJoin(predictionOutcomes, eq(predictionEvents.id, predictionOutcomes.predictionId))
        .where(eq(predictionEvents.userId, userId))
        .orderBy(desc(predictionEvents.createdAt))
        .limit(limit)
        .offset(offset);

      // Get user's overall stats
      const userStats = await db.select({
        total: sql`count(*)`,
        wins: sql`count(*) filter (where ${predictionOutcomes.isCorrect} = true)`,
        avgReturn: sql`avg(cast(${predictionOutcomes.priceChangePercent} as decimal))`
      })
        .from(predictionEvents)
        .leftJoin(predictionOutcomes, eq(predictionEvents.id, predictionOutcomes.predictionId))
        .where(eq(predictionEvents.userId, userId));

      res.json({
        predictions: predictions.map(p => ({
          id: p.id,
          ticker: p.ticker,
          signal: p.signal,
          confidence: Number(p.confidence || 0),
          priceAtPrediction: p.priceAtPrediction,
          createdAt: p.createdAt?.toISOString(),
          outcome: p.isCorrect !== null ? {
            horizon: p.horizon,
            isCorrect: p.isCorrect,
            priceChangePercent: p.priceChangePercent,
            evaluatedAt: p.evaluatedAt?.toISOString()
          } : null
        })),
        userStats: {
          totalPredictions: Number(userStats[0]?.total || 0),
          wins: Number(userStats[0]?.wins || 0),
          accuracy: userStats[0]?.total ?
            (Number(userStats[0].wins) / Number(userStats[0].total) * 100).toFixed(1) : '0.0',
          avgReturn: Number(userStats[0]?.avgReturn || 0).toFixed(2)
        },
        pagination: {
          limit,
          offset,
          hasMore: predictions.length === limit
        }
      });
    } catch (error) {
      console.error("ML user history error:", error);
      res.status(500).json({ error: "Failed to fetch user history" });
    }
  });

  // ==============================================
  // VEIL E-READER CHAPTERS API (server-side parsing)
  // ==============================================

  let cachedVeilChapters: any = null;
  let cachedVeilMtime: number = 0;

  let cachedSpeakingCodeChapters: any = null;
  let cachedSpeakingCodeMtime: number = 0;

  function parseVeilMarkdown(markdown: string) {
    const lines = markdown.split('\n');
    const chapters: { id: string; title: string; content: string; partTitle: string }[] = [];
    let currentChapter: { id: string; title: string; content: string; partTitle: string } | null = null;
    let currentContent: string[] = [];
    let currentPart = "";
    let inFrontMatter = true;
    let frontMatterContent: string[] = [];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];

      if (line.match(/^# PART [IVXLC]+[-]?[A-Z]?:/i) || line.match(/^# PART (ONE|TWO|THREE|FOUR|FIVE|SIX|SEVEN|EIGHT|NINE|TEN|ELEVEN|TWELVE)[-]?[A-Z]?:/i)) {
        currentPart = line.replace(/^# /, '').trim();
        continue;
      }

      const chapterMatch = line.match(/^# (CHAPTER \d+[A-Z]?:.+)$/i);
      const appendixMatch = line.match(/^# (APPENDIX[^:]*:.*)$/i) || line.match(/^# (APPENDIX.*)$/i);

      if (chapterMatch || appendixMatch) {
        inFrontMatter = false;
        if (currentChapter) {
          currentChapter.content = currentContent.join('\n').trim();
          chapters.push(currentChapter);
        }
        const title = (chapterMatch ? chapterMatch[1] : appendixMatch![1]).trim();
        const id = 'ch-' + title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/-+/g, '-').substring(0, 50);
        if (appendixMatch && !currentPart.includes('APPENDIX')) {
          currentPart = 'APPENDIX: Reference Materials';
        }
        currentChapter = { id, title, content: '', partTitle: currentPart };
        currentContent = [];
        continue;
      }

      if (line.match(/^## TABLE OF CONTENTS/i)) {
        while (i < lines.length - 1 && !lines[i + 1].match(/^# PART/i)) { i++; }
        continue;
      }

      if (inFrontMatter && !line.match(/^# PART/)) {
        frontMatterContent.push(line);
      }

      if (currentChapter) {
        currentContent.push(line);
      }
    }

    if (currentChapter) {
      currentChapter.content = currentContent.join('\n').trim();
      chapters.push(currentChapter);
    }

    const frontMatterSections: typeof chapters = [];
    const fmText = frontMatterContent.join('\n');
    const fmSectionRegex = /^## (.+)$/gm;
    const fmSectionMatches: { title: string; start: number }[] = [];
    let fmMatch;
    while ((fmMatch = fmSectionRegex.exec(fmText)) !== null) {
      const title = fmMatch[1].trim();
      if (title.toUpperCase() === 'TABLE OF CONTENTS') continue;
      fmSectionMatches.push({ title, start: fmMatch.index });
    }

    const fmSectionNames = new Set(fmSectionMatches.map(s => s.title.toLowerCase()));
    const titlePageSections = ['the greatest story ever stole?', 'the greatest story ever stole'];
    let titlePageEnd = fmSectionMatches.length > 0 ? fmSectionMatches[0].start : fmText.length;
    let firstContentSection = 0;
    if (fmSectionMatches.length > 0 && titlePageSections.includes(fmSectionMatches[0].title.toLowerCase())) {
      firstContentSection = 1;
      titlePageEnd = fmSectionMatches.length > 1 ? fmSectionMatches[1].start : fmText.length;
    }
    let titleContent = fmText.substring(0, titlePageEnd).trim();
    if (!titleContent.startsWith('# ')) {
      titleContent = '# THROUGH THE VEIL\n\n' + titleContent;
    }
    if (titleContent.length > 20) {
      frontMatterSections.push({
        id: 'fm-title',
        title: 'Title Page',
        content: titleContent,
        partTitle: 'Front Matter'
      });
    }

    for (let s = firstContentSection; s < fmSectionMatches.length; s++) {
      const sec = fmSectionMatches[s];
      const nextStart = s + 1 < fmSectionMatches.length ? fmSectionMatches[s + 1].start : fmText.length;
      const secContent = fmText.substring(sec.start, nextStart).trim();
      if (secContent.length > 10) {
        frontMatterSections.push({
          id: 'fm-' + sec.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/-+/g, '-').substring(0, 40),
          title: sec.title,
          content: secContent,
          partTitle: 'Front Matter'
        });
      }
    }

    if (frontMatterSections.length === 0 && frontMatterContent.join('\n').trim().length > 0) {
      frontMatterSections.push({
        id: 'front-matter',
        title: 'Introduction & Front Matter',
        content: frontMatterContent.join('\n').trim(),
        partTitle: 'Front Matter'
      });
    }

    const partMap = new Map<string, typeof chapters>();
    partMap.set('Front Matter', frontMatterSections);

    for (const chapter of chapters) {
      const part = chapter.partTitle || 'Main Content';
      if (!partMap.has(part)) partMap.set(part, []);
      partMap.get(part)!.push(chapter);
    }

    const volumes: { id: string; title: string; subtitle: string; chapters: typeof chapters }[] = [];
    let volumeIndex = 0;

    for (const [partTitle, partChapters] of Array.from(partMap.entries())) {
      if (partChapters.length === 0) continue;
      volumes.push({
        id: `volume-${volumeIndex}`,
        title: partTitle === 'Front Matter' ? 'Front Matter' : partTitle,
        subtitle: partTitle === 'Front Matter'
          ? `${partChapters.length} sections — introduction, dedication, and author notes`
          : `${partChapters.length} chapter${partChapters.length > 1 ? 's' : ''}`,
        chapters: partChapters
      });
      volumeIndex++;
    }

    return volumes;
  }

  app.get("/api/veil/chapters", async (req, res) => {
    try {
      const preview = req.query.preview === "true";
      const mdPaths = [
        path.join(process.cwd(), "client", "public", "through-the-veil.md"),
        path.join(process.cwd(), "public", "through-the-veil.md"),
        path.join(process.cwd(), "dist", "public", "through-the-veil.md"),
      ];

      let mdContent = '';
      let mdMtime = 0;
      for (const mdPath of mdPaths) {
        if (fs.existsSync(mdPath)) {
          const stat = fs.statSync(mdPath);
          mdMtime = stat.mtimeMs;
          if (cachedVeilChapters && mdMtime === cachedVeilMtime) {
            let volumes = cachedVeilChapters;
            if (preview && Array.isArray(volumes)) {
              volumes = volumes.slice(0, 1).map((v: any) => ({
                ...v,
                chapters: v.chapters?.slice(0, 4) || [],
              }));
            }
            res.setHeader('Cache-Control', 'public, max-age=60');
            return res.json(volumes);
          }
          mdContent = fs.readFileSync(mdPath, 'utf-8');
          break;
        }
      }

      if (!mdContent) {
        return res.status(404).json({ error: "Ebook content not found" });
      }

      let volumes = parseVeilMarkdown(mdContent);
      cachedVeilChapters = volumes;
      cachedVeilMtime = mdMtime;
      if (preview && Array.isArray(volumes)) {
        volumes = volumes.slice(0, 1).map((v: any) => ({
          ...v,
          chapters: v.chapters?.slice(0, 4) || [],
        }));
      }
      res.setHeader('Cache-Control', 'public, max-age=60');
      res.json(volumes);
    } catch (error: any) {
      console.error("Veil chapters API error:", error);
      res.status(500).json({ error: "Failed to parse ebook", details: error.message });
    }
  });

  app.get("/api/veil/toc", async (req, res) => {
    try {
      const preview = req.query.preview === "true";
      const mdPaths = [
        path.join(process.cwd(), "client", "public", "through-the-veil.md"),
        path.join(process.cwd(), "public", "through-the-veil.md"),
        path.join(process.cwd(), "dist", "public", "through-the-veil.md"),
      ];

      let mdContent = '';
      let mdMtime = 0;
      for (const mdPath of mdPaths) {
        if (fs.existsSync(mdPath)) {
          const stat = fs.statSync(mdPath);
          mdMtime = stat.mtimeMs;
          if (cachedVeilChapters && mdMtime === cachedVeilMtime) {
            let volumes = cachedVeilChapters;
            if (preview && Array.isArray(volumes)) {
              volumes = volumes.slice(0, 1).map((v: any) => ({
                ...v,
                chapters: v.chapters?.slice(0, 4) || [],
              }));
            }
            const toc = volumes.map((v: any) => ({
              id: v.id,
              title: v.title,
              subtitle: v.subtitle,
              chapters: v.chapters.map((c: any) => ({ id: c.id, title: c.title, partTitle: c.partTitle })),
            }));
            res.setHeader('Cache-Control', 'public, max-age=300');
            return res.json(toc);
          }
          mdContent = fs.readFileSync(mdPath, 'utf-8');
          break;
        }
      }

      if (!mdContent) {
        return res.status(404).json({ error: "Ebook content not found" });
      }

      let volumes = parseVeilMarkdown(mdContent);
      cachedVeilChapters = volumes;
      cachedVeilMtime = mdMtime;

      if (preview && Array.isArray(volumes)) {
        volumes = volumes.slice(0, 1).map((v: any) => ({
          ...v,
          chapters: v.chapters?.slice(0, 4) || [],
        }));
      }

      const toc = volumes.map((v: any) => ({
        id: v.id,
        title: v.title,
        subtitle: v.subtitle,
        chapters: v.chapters.map((c: any) => ({ id: c.id, title: c.title, partTitle: c.partTitle })),
      }));
      res.setHeader('Cache-Control', 'public, max-age=300');
      res.json(toc);
    } catch (error: any) {
      console.error("Veil TOC API error:", error);
      res.status(500).json({ error: "Failed to parse ebook TOC", details: error.message });
    }
  });

  app.get("/api/veil/chapter/:volIndex/:chapIndex", async (req, res) => {
    try {
      const volIndex = parseInt(req.params.volIndex, 10);
      const chapIndex = parseInt(req.params.chapIndex, 10);

      if (isNaN(volIndex) || isNaN(chapIndex) || volIndex < 0 || chapIndex < 0) {
        return res.status(400).json({ error: "Invalid volume or chapter index" });
      }

      const mdPaths = [
        path.join(process.cwd(), "client", "public", "through-the-veil.md"),
        path.join(process.cwd(), "public", "through-the-veil.md"),
        path.join(process.cwd(), "dist", "public", "through-the-veil.md"),
      ];

      let mdContent = '';
      let mdMtime = 0;
      for (const mdPath of mdPaths) {
        if (fs.existsSync(mdPath)) {
          const stat = fs.statSync(mdPath);
          mdMtime = stat.mtimeMs;
          if (!cachedVeilChapters || mdMtime !== cachedVeilMtime) {
            mdContent = fs.readFileSync(mdPath, 'utf-8');
          }
          break;
        }
      }

      if (mdContent) {
        cachedVeilChapters = parseVeilMarkdown(mdContent);
        cachedVeilMtime = mdMtime;
      }

      if (!cachedVeilChapters) {
        return res.status(404).json({ error: "Ebook content not found" });
      }

      const volumes = cachedVeilChapters as any[];
      if (volIndex >= volumes.length) {
        return res.status(404).json({ error: "Volume not found" });
      }
      if (chapIndex >= volumes[volIndex].chapters.length) {
        return res.status(404).json({ error: "Chapter not found" });
      }

      const chapter = volumes[volIndex].chapters[chapIndex];
      res.setHeader('Cache-Control', 'public, max-age=300');
      res.json({
        id: chapter.id,
        title: chapter.title,
        content: chapter.content,
        partTitle: chapter.partTitle,
      });
    } catch (error: any) {
      console.error("Veil chapter API error:", error);
      res.status(500).json({ error: "Failed to load chapter", details: error.message });
    }
  });

