  app.post("/api/voice/tts", async (req, res) => {
    try {
      if (!process.env.ELEVEN_LABS_API_KEY && !process.env.ELEVENLABS_API_KEY) {
         return res.status(500).json({ error: 'ElevenLabs API key not configured' });
      }

      const { text, voiceId = "21m00Tcm4TlvDq8ikWAM" } = req.body; // Default "Rachel"

      const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`, {
        method: "POST",
        headers: {
          "Accept": "audio/mpeg",
          "Content-Type": "application/json",
          "xi-api-key": process.env.ELEVEN_LABS_API_KEY || process.env.ELEVENLABS_API_KEY || ""
        },
        body: JSON.stringify({
          text,
          model_id: "eleven_monolingual_v1",
          voice_settings: { stability: 0.5, similarity_boost: 0.5 }
        })
      });

      if (!response.ok) {
        throw new Error(`ElevenLabs API returned ${response.status}`);
      }

      const audioBuffer = await response.arrayBuffer();
      res.setHeader('Content-Type', 'audio/mpeg');
      res.send(Buffer.from(audioBuffer));
    } catch (error: any) {
      console.error("[TTS Proxy] Error:", error);
      res.status(500).json({ error: "Failed to generate TTS audio" });
    }
  });

