  function generateEcosystemAffiliateId(): string {
    const timestamp = Date.now().toString(36);
    const random = crypto.randomBytes(4).toString("hex");
    return `tl-${timestamp}-${random}`;
  }

  const ECOSYSTEM_AFFILIATE_ID_REGEX = /^(tldc|he|tl)-[a-z0-9]+-[a-f0-9]{8}$/;
  const GARAGEBOT_AFFILIATE_ID_REGEX = /^GB-[ABCDEFGHJKLMNPQRSTUVWXYZ2-9]{6}$/;

  function isValidEcosystemAffiliateId(id: string): boolean {
    return ECOSYSTEM_AFFILIATE_ID_REGEX.test(id) || GARAGEBOT_AFFILIATE_ID_REGEX.test(id);
  }

