  app.get("/api/affiliates/lookup/:code", async (req: Request, res: Response) => {
    try {
      const { code } = req.params;

      if (!isValidEcosystemAffiliateId(code)) {
        return res.status(400).json({ error: "Invalid affiliate code format" });
      }

      const platform = code.startsWith("GB-") ? "garagebot"
        : code.startsWith("tldc-") ? "tldc"
          : code.startsWith("he-") ? "he"
            : "tl";

      if (platform === "tl") {
        const [affiliate] = await db.select().from(ecosystemAffiliates)
          .where(eq(ecosystemAffiliates.trustLayerId, code)).limit(1);
        if (!affiliate) {
          return res.status(404).json({ error: "Affiliate not found on Trust Layer" });
        }
        return res.json({
          source: "trust_layer",
          platform: "tl",
          affiliateCode: code,
          data: {
            name: affiliate.name,
            status: affiliate.status,
            totalReferrals: affiliate.totalReferrals,
            qualifiedReferrals: affiliate.qualifiedReferrals,
            totalEarningsCents: affiliate.totalEarningsCents,
            pendingBalanceCents: affiliate.pendingBalanceCents,
            createdAt: affiliate.createdAt,
          }
        });
      }

      if (platform === "garagebot") {
        const localRecord = await db.select().from(ecosystemAffiliates)
          .where(eq(ecosystemAffiliates.trustLayerId, code)).limit(1);

        try {
          const baseUrl = ECOSYSTEM_APP_URLS.garagebot;
          const response = await fetch(`${baseUrl}/api/affiliate-program/trustlayer/${code}`, {
            signal: AbortSignal.timeout(8000),
          });

          if (response.ok) {
            const remoteData = await response.json();
            return res.json({
              source: "garagebot",
              platform: "garagebot",
              affiliateCode: code,
              localRecord: localRecord[0] || null,
              remoteData
            });
          }

          if (response.status === 404) {
            if (localRecord[0]) {
              return res.json({ source: "trust_layer_local", platform: "garagebot", affiliateCode: code, localRecord: localRecord[0], remoteData: null, note: "Affiliate registered locally but not found on GarageBot" });
            }
            return res.status(404).json({ error: "Affiliate not found on GarageBot or Trust Layer" });
          }
        } catch (fetchErr: any) {
          if (localRecord[0]) {
            return res.json({ source: "trust_layer_local", platform: "garagebot", affiliateCode: code, localRecord: localRecord[0], remoteData: null, note: "GarageBot API unreachable — showing local record only" });
          }
          return res.status(502).json({ error: "GarageBot API unreachable and no local record found" });
        }

        return res.status(502).json({ error: "Failed to reach GarageBot affiliate API" });
      }

      return res.json({
        source: "external",
        platform,
        affiliateCode: code,
        data: null,
        note: `Affiliate data for ${platform} platform codes must be queried from the originating platform directly.`
      });
    } catch (error: any) {
      if (error?.name === "TimeoutError" || error?.name === "AbortError") {
        return res.status(504).json({ error: "External platform request timed out" });
      }
      console.error("Affiliate lookup error:", error);
      res.status(500).json({ error: "Failed to look up affiliate" });
    }
  });

  app.post("/api/affiliates/register", async (req: Request, res: Response) => {
    try {
      const { trustLayerId, name, email, phone, source } = req.body;

      if (!name || typeof name !== "string") {
        return res.status(400).json({ error: "Name is required" });
      }

      let affiliateId = trustLayerId;
      if (!affiliateId) {
        affiliateId = generateEcosystemAffiliateId();
      }

      if (!isValidEcosystemAffiliateId(affiliateId)) {
        return res.status(400).json({ error: "Invalid affiliate ID format. Must match ecosystem standard (tldc-/he-/tl-) or GarageBot (GB-XXXXXX) format." });
      }

      const existing = await db.select().from(ecosystemAffiliates)
        .where(eq(ecosystemAffiliates.trustLayerId, affiliateId)).limit(1);
      if (existing.length > 0) {
        return res.status(409).json({ error: "Affiliate ID already registered", affiliate: existing[0] });
      }

      const [affiliate] = await db.insert(ecosystemAffiliates).values({
        trustLayerId: affiliateId,
        name: name.trim(),
        email: email?.trim() || null,
        phone: phone?.trim() || null,
        source: source || affiliateId.split("-")[0],
        status: "active",
      }).returning();

      res.status(201).json({ affiliate });
    } catch (error) {
      console.error("Affiliate register error:", error);
      res.status(500).json({ error: "Failed to register affiliate" });
    }
  });

