  function verifyEcosystemApiAuth(req: Request, res: Response): boolean {
    const apiKey = req.headers["x-api-key"] as string;
    const signature = req.headers["x-api-signature"] as string;
    const timestamp = req.headers["x-api-timestamp"] as string;
    const serverKey = process.env.TRUSTLAYER_API_KEY;
    const serverSecret = process.env.TRUSTLAYER_API_SECRET;

    if (!serverKey || !serverSecret) {
      res.status(503).json({ error: "Ecosystem API not configured" });
      return false;
    }

    if (!apiKey || !signature || !timestamp) {
      res.status(401).json({ error: "Missing API authentication headers (x-api-key, x-api-signature, x-api-timestamp)" });
      return false;
    }

    if (apiKey !== serverKey) {
      res.status(401).json({ error: "Invalid API key" });
      return false;
    }

    const requestTime = parseInt(timestamp);
    if (isNaN(requestTime) || Math.abs(Date.now() - requestTime) > 5 * 60 * 1000) {
      res.status(401).json({ error: "Request expired or invalid timestamp" });
      return false;
    }

    const expectedSig = crypto.createHmac("sha256", serverSecret)
      .update(`${apiKey}${timestamp}`)
      .digest("hex");

    const sigBuffer = Buffer.from(signature);
    const expectedBuffer = Buffer.from(expectedSig);
    if (sigBuffer.length !== expectedBuffer.length || !crypto.timingSafeEqual(sigBuffer, expectedBuffer)) {
      res.status(401).json({ error: "Invalid signature" });
      return false;
    }

    return true;
  }

  app.post("/api/affiliates/referrals", async (req: Request, res: Response) => {
    try {
      if (!verifyEcosystemApiAuth(req, res)) return;

      const { affiliateId, referredType, referredName, referredEmail, referredEntityId, platform } = req.body;

      if (!affiliateId || !referredName) {
        return res.status(400).json({ error: "affiliateId and referredName are required" });
      }

      const result = await db.transaction(async (tx) => {
        const [affiliate] = await tx.select().from(ecosystemAffiliates)
          .where(eq(ecosystemAffiliates.id, affiliateId)).limit(1);

        if (!affiliate) {
          throw new Error("AFFILIATE_NOT_FOUND");
        }

        const [referral] = await tx.insert(ecosystemReferrals).values({
          affiliateId,
          referredType: referredType || "vendor",
          referredName: referredName.trim(),
          referredEmail: referredEmail?.trim() || null,
          referredEntityId: referredEntityId || null,
          platform: platform || "tl",
          status: "pending",
        }).returning();

        const [reward] = await tx.insert(ecosystemRewardsLedger).values({
          affiliateId,
          referralId: referral.id,
          type: "vendor_referral",
          amountCents: 2000,
          description: `$20 one-time bonus for referring ${referredName}`,
          status: "held",
        }).returning();

        await tx.update(ecosystemAffiliates)
          .set({ totalReferrals: sql`${ecosystemAffiliates.totalReferrals} + 1`, updatedAt: new Date() })
          .where(eq(ecosystemAffiliates.id, affiliateId));

        return { referral, reward };
      });

      res.status(201).json(result);
    } catch (error: any) {
      if (error?.message === "AFFILIATE_NOT_FOUND") {
        return res.status(404).json({ error: "Affiliate not found" });
      }
      console.error("Create referral error:", error);
      res.status(500).json({ error: "Failed to create referral" });
    }
  });

  app.post("/api/affiliates/referrals/:id/activate", async (req: Request, res: Response) => {
    try {
      if (!verifyEcosystemApiAuth(req, res)) return;

      const referralId = parseInt(req.params.id);
      if (isNaN(referralId)) {
        return res.status(400).json({ error: "Invalid referral ID" });
      }

      const result = await db.transaction(async (tx) => {
        const [referral] = await tx.select().from(ecosystemReferrals)
          .where(eq(ecosystemReferrals.id, referralId)).limit(1);

        if (!referral) {
          throw new Error("REFERRAL_NOT_FOUND");
        }

        if (referral.status === "active") {
          throw new Error("ALREADY_ACTIVATED");
        }

        if (referral.daysActive < 14 || referral.revenueGeneratedCents < 10000) {
          throw new Error("ACTIVATION_REQUIREMENTS_NOT_MET");
        }

        await tx.update(ecosystemReferrals)
          .set({ status: "active", activatedAt: new Date() })
          .where(eq(ecosystemReferrals.id, referralId));

        await tx.update(ecosystemRewardsLedger)
          .set({ status: "pending" })
          .where(and(
            eq(ecosystemRewardsLedger.referralId, referralId),
            eq(ecosystemRewardsLedger.status, "held")
          ));

        const [affiliate] = await tx.select().from(ecosystemAffiliates)
          .where(eq(ecosystemAffiliates.id, referral.affiliateId)).limit(1);

        const newQualified = (affiliate?.qualifiedReferrals || 0) + 1;

        await tx.update(ecosystemAffiliates)
          .set({
            qualifiedReferrals: newQualified,
            totalEarningsCents: sql`${ecosystemAffiliates.totalEarningsCents} + 2000`,
            pendingBalanceCents: sql`${ecosystemAffiliates.pendingBalanceCents} + 2000`,
            updatedAt: new Date(),
          })
          .where(eq(ecosystemAffiliates.id, referral.affiliateId));

        return {
          message: "Referral activated successfully",
          referralId,
          affiliateId: referral.affiliateId,
          newQualifiedCount: newQualified,
          currentTier: newQualified >= 10 ? "Builder" : "Starter",
          revenueSharePercent: newQualified >= 10 ? 2 : 1,
          bonusUnlocked: 2000,
        };
      });

      res.json(result);
    } catch (error: any) {
      if (error?.message === "REFERRAL_NOT_FOUND") {
        return res.status(404).json({ error: "Referral not found" });
      }
      if (error?.message === "ALREADY_ACTIVATED") {
        return res.status(400).json({ error: "Referral is already activated" });
      }
      if (error?.message === "ACTIVATION_REQUIREMENTS_NOT_MET") {
        return res.status(400).json({ error: "Vendor must be active for 14+ days AND generate $100+ in revenue before activation" });
      }
      console.error("Activate referral error:", error);
      res.status(500).json({ error: "Failed to activate referral" });
    }
  });

  // ============================================================
  // THE VOID — Void ID System, DW-STAMP-1.0 & Bridge API
  // ============================================================

  function generateVoidId(): string {
    const digits = Array.from({ length: 8 }, () => Math.floor(Math.random() * 10)).join('');
    return `V-${digits}`;
  }

  function generateTrustLayerId(): string {
    const ts = Date.now().toString(36);
    const rand = crypto.randomBytes(4).toString('hex');
    return `tl-${ts}-${rand}`;
  }

  function computeStampHash(data: { voidId: string; userId: number; block: number; prev: string | null; ts: string }): string {
    const input = JSON.stringify({
      voidId: data.voidId,
      userId: data.userId,
      block: data.block,
      prev: data.prev,
      ts: data.ts,
      issuer: "darkwave-studios-void",
      network: "trust-layer-v1",
    });
    return crypto.createHash("sha256").update(input).digest("hex");
  }

  app.get("/api/stamp/verify/:voidId", async (req: Request, res: Response) => {
    try {
      const { voidId } = req.params;
      if (!voidId || !voidId.startsWith("V-")) {
        return res.json({ valid: false });
      }

      const stampResult = await db.execute(
        sql`SELECT * FROM void_stamps WHERE void_id = ${voidId} ORDER BY block_number DESC LIMIT 1`
      );
      const stamp = stampResult.rows?.[0];
      if (!stamp) {
        return res.json({ valid: false });
      }

      const recomputedHash = computeStampHash({
        voidId: stamp.void_id as string,
        userId: stamp.user_id as number,
        block: stamp.block_number as number,
        prev: stamp.previous_hash as string | null,
        ts: (stamp.created_at as Date).toISOString(),
      });
      const hashMatch = recomputedHash === stamp.stamp_hash;

      let chainIntegrity = true;
      if ((stamp.block_number as number) > 1 && stamp.previous_hash) {
        const prevResult = await db.execute(
          sql`SELECT stamp_hash FROM void_stamps WHERE block_number = ${(stamp.block_number as number) - 1} ORDER BY id DESC LIMIT 1`
        );
        if (prevResult.rows?.[0]) {
          chainIntegrity = prevResult.rows[0].stamp_hash === stamp.previous_hash;
        }
      }

      const payload = stamp.payload as any;

      res.json({
        valid: true,
        stamp: {
          voidId: stamp.void_id,
          userId: stamp.user_id,
          stampHash: stamp.stamp_hash,
          blockNumber: stamp.block_number,
          previousHash: stamp.previous_hash,
          payload,
          verified: stamp.verified,
          createdAt: stamp.created_at,
        },
        verification: {
          hashMatch,
          chainIntegrity,
          issuer: payload?.issuer || "DarkWave Studios",
          network: payload?.network || "Trust Layer v1",
          blockNumber: stamp.block_number,
          mintedAt: stamp.created_at,
        },
      });
    } catch (error) {
      console.error("Stamp verify error:", error);
      res.json({ valid: false });
    }
  });

  app.post("/api/bridge/link-void", async (req: Request, res: Response) => {
    try {
      const { chatUserId, userId } = req.body;
      if (!chatUserId || !userId) {
        return res.status(400).json({ error: "chatUserId and userId are required" });
      }

      const existingVoid = await db.execute(
        sql`SELECT void_id FROM void_ids WHERE user_id = ${userId} AND status = 'active' LIMIT 1`
      );
      let voidId: string;
      if (existingVoid.rows?.length > 0) {
        voidId = existingVoid.rows[0].void_id as string;
      } else {
        let attempts = 0;
        do {
          voidId = generateVoidId();
          const exists = await db.execute(sql`SELECT 1 FROM void_ids WHERE void_id = ${voidId}`);
          if (!exists.rows?.length) break;
          attempts++;
        } while (attempts < 10);

        await db.execute(
          sql`INSERT INTO void_ids (void_id, user_id, status) VALUES (${voidId}, ${userId}, 'active')`
        );

        const lastStamp = await db.execute(
          sql`SELECT stamp_hash, block_number FROM void_stamps ORDER BY block_number DESC LIMIT 1`
        );
        const blockNumber = lastStamp.rows?.length ? (lastStamp.rows[0].block_number as number) + 1 : 1;
        const previousHash = lastStamp.rows?.length ? (lastStamp.rows[0].stamp_hash as string) : null;
        const mintedAt = new Date().toISOString();

        const stampHash = computeStampHash({
          voidId,
          userId,
          block: blockNumber,
          prev: previousHash,
          ts: mintedAt,
        });

        const payload = {
          voidId,
          userId,
          issuer: "DarkWave Studios",
          network: "Trust Layer v1",
          type: "VOID_PREMIUM_HALLMARK",
          mintedAt,
          ecosystem: "darkwave",
          standard: "DW-STAMP-1.0",
        };

        await db.execute(
          sql`INSERT INTO void_stamps (void_id, user_id, stamp_hash, block_number, previous_hash, payload, verified)
              VALUES (${voidId}, ${userId}, ${stampHash}, ${blockNumber}, ${previousHash}, ${JSON.stringify(payload)}, true)`
        );
      }

      const trustLayerId = generateTrustLayerId();

      const existingBridge = await db.execute(
        sql`SELECT id FROM void_bridge_links WHERE chat_user_id = ${chatUserId}`
      );
      if (existingBridge.rows?.length) {
        await db.execute(
          sql`UPDATE void_bridge_links SET void_id = ${voidId}, trust_layer_id = ${trustLayerId} WHERE chat_user_id = ${chatUserId}`
        );
      } else {
        await db.execute(
          sql`INSERT INTO void_bridge_links (chat_user_id, user_id, trust_layer_id, void_id, role)
              VALUES (${chatUserId}, ${userId}, ${trustLayerId}, ${voidId}, 'member')`
        );
      }

      res.json({ success: true, voidId, message: `Void ID ${voidId} linked successfully` });
    } catch (error) {
      console.error("Bridge link-void error:", error);
      res.status(500).json({ error: "Failed to link Void ID" });
    }
  });

